use beads_rust::format::markdown::render_markdown;
use beads_rust::format::OutputContext;

#[test]
fn test_markdown_bold_rendered() {
    let ctx = OutputContext::rich();
    let output = render_markdown("**bold text**", &ctx);
    // Should have ANSI bold codes
    assert!(output.contains("bold text"));
}

#[test]
fn test_markdown_code_block() {
    let ctx = OutputContext::rich();
    let input = "```rust\nfn main() {}\n```";
    let output = render_markdown(input, &ctx);
    assert!(output.contains("fn main"));
}

#[test]
fn test_markdown_plain_mode_strips() {
    let ctx = OutputContext::plain();
    let output = render_markdown("**bold** and *italic*", &ctx);
    // Should strip markdown formatting
    assert!(output.contains("bold"));
    assert!(!output.contains("**"));
}

#[test]
fn test_markdown_json_mode_unchanged() {
    let ctx = OutputContext::json();
    let input = "**bold** text";
    let output = render_markdown(input, &ctx);
    // Should return raw markdown
    assert_eq!(output, input);
}

#[test]
fn test_markdown_inline_code() {
    let ctx = OutputContext::rich();
    let output = render_markdown("use `println!` for output", &ctx);
    assert!(output.contains("println!"));
}

#[test]
fn test_markdown_lists() {
    let ctx = OutputContext::rich();
    let input = "- item 1\n- item 2";
    let output = render_markdown(input, &ctx);
    assert!(output.contains("item 1"));
    assert!(output.contains("item 2"));
}

#[test]
fn test_markdown_links() {
    let ctx = OutputContext::rich();
    let input = "[link](https://example.com)";
    let output = render_markdown(input, &ctx);
    assert!(output.contains("link"));
}

#[test]
fn test_markdown_empty_input() {
    let ctx = OutputContext::rich();
    let output = render_markdown("", &ctx);
    assert!(output.is_empty() || output.trim().is_empty());
}

#[test]
fn test_markdown_no_panic_on_malformed() {
    let ctx = OutputContext::rich();
    // Various malformed inputs that shouldn't panic
    let _ = render_markdown("```unclosed code block", &ctx);
    let _ = render_markdown("**unclosed bold", &ctx);
    let _ = render_markdown("[broken link(", &ctx);
}
